+import Yoga from 'yoga-layout';
+import {type DOMElement} from './dom.js';
+
+type Track =
+	| {kind: 'fixed'; value: number}
+	| {kind: 'fr'; value: number; min: number}
+	| {kind: 'auto'};
+
+type Placement = {start: number; end: number};
+
+const parseTrackList = (template: string | undefined): Track[] => {
+	if (!template) return [];
+	const tokens = template.match(/minmax\\([^)]*\\)|\\S+/g) ?? [];
+	return tokens.map(token => {
+		if (token === 'auto') return {kind: 'auto'};
+		const minmax = /^minmax\\(\\s*([\\d.]+)\\s*,\\s*([\\d.]+(?:fr)?)\\s*\\)$/.exec(token);
+		if (minmax) {
+			const min = Number(minmax[1]);
+			const max = minmax[2];
+			return max.endsWith('fr')
+				? {kind: 'fr', value: Number.parseFloat(max), min}
+				: {kind: 'fixed', value: Number(max)};
+		}
+		if (token.endsWith('fr')) {
+			return {kind: 'fr', value: Number.parseFloat(token) || 1, min: 0};
+		}
+		return {kind: 'fixed', value: Number(token)};
+	});
+};
+
+const parsePlacement = (value: number | string | undefined): Placement | undefined => {
+	if (typeof value === 'number') return {start: value - 1, end: value};
+	if (!value) return;
+	const match = /^\\s*(\\d+)\\s*\\/\\s*(\\d+)\\s*$/.exec(value);
+	if (match) return {start: Number(match[1]) - 1, end: Number(match[2]) - 1};
+	const line = Number(value);
+	return Number.isFinite(line) ? {start: line - 1, end: line} : undefined;
+};
+
+const sizeTracks = (tracks: Track[], available: number, gap: number, autoSizes: number[]): number[] => {
+	const base = tracks.map((track, index) => track.kind === 'fixed' ? track.value : track.kind === 'fr' ? track.min : autoSizes[index] ?? 0);
+	const free = Math.max(0, available - base.reduce((sum, size) => sum + size, 0) - Math.max(0, tracks.length - 1) * gap);
+	const factor = tracks.reduce((sum, track) => sum + (track.kind === 'fr' ? track.value : 0), 0);
+	return tracks.map((track, index) => track.kind === 'fr' && factor > 0 ? base[index] + free * track.value / factor : base[index]);
+};
+
+const offsets = (sizes: number[], gap: number): number[] => {
+	let offset = 0;
+	return sizes.map(size => {
+		const current = offset;
+		offset += size + gap;
+		return current;
+	});
+};
+
+const spanSize = (sizes: number[], start: number, end: number, gap: number): number =>
+	sizes.slice(start, end).reduce((sum, size) => sum + size, 0) + Math.max(0, end - start - 1) * gap;
+
+const layoutGrid = (node: DOMElement): void => {
+	for (const child of node.childNodes) {
+		if (child.nodeName !== '#text') layoutGrid(child);
+	}
+	if (node.style.display !== 'grid' || !node.yogaNode) return;
+
+	const children = node.childNodes.filter((child): child is DOMElement => child.nodeName !== '#text' && Boolean(child.yogaNode));
+	let columns = parseTrackList(node.style.gridTemplateColumns);
+	if (columns.length === 0) columns = [{kind: 'auto'}];
+	const columnGap = node.style.columnGap ?? node.style.gap ?? 0;
+	const rowGap = node.style.rowGap ?? node.style.gap ?? 0;
+	const occupied = new Set<string>();
+	const placements: Array<{child: DOMElement; column: Placement; row: Placement}> = [];
+	let cursor = 0;
+	for (const child of children) {
+		let column = parsePlacement(child.style.gridColumn);
+		let row = parsePlacement(child.style.gridRow);
+		if (!column || !row) {
+			while (occupied.has(`${Math.floor(cursor / columns.length)}:${cursor % columns.length}`)) cursor++;
+			const autoRow = Math.floor(cursor / columns.length);
+			const autoColumn = cursor % columns.length;
+			column ??= {start: autoColumn, end: autoColumn + 1};
+			row ??= {start: autoRow, end: autoRow + 1};
+		}
+		for (let y = row.start; y < row.end; y++) for (let x = column.start; x < column.end; x++) occupied.add(`${y}:${x}`);
+		placements.push({child, column, row});
+	}
+
+	let rows = parseTrackList(node.style.gridTemplateRows);
+	const requiredRows = Math.max(0, ...placements.map(item => item.row.end));
+	while (rows.length < requiredRows) rows.push({kind: 'auto'});
+	const layout = node.yogaNode.getComputedLayout();
+	const columnAuto = columns.map((_, index) => Math.max(0, ...placements.filter(item => item.column.start === index && item.column.end === index + 1).map(item => item.child.yogaNode!.getComputedLayout().width)));
+	const columnSizes = sizeTracks(columns, layout.width, columnGap, columnAuto);
+	const rowAuto = rows.map((_, index) => Math.max(0, ...placements.filter(item => item.row.start === index && item.row.end === index + 1).map(item => item.child.yogaNode!.getComputedLayout().height)));
+	const specifiedHeight = typeof node.style.height === 'number' ? node.style.height : layout.height;
+	const rowSizes = sizeTracks(rows, specifiedHeight, rowGap, rowAuto);
+	const columnOffsets = offsets(columnSizes, columnGap);
+	const rowOffsets = offsets(rowSizes, rowGap);
+	const contentHeight = rowSizes.reduce((sum, size) => sum + size, 0) + Math.max(0, rowSizes.length - 1) * rowGap;
+	if (node.style.height === undefined) node.yogaNode.setHeight(contentHeight);
+
+	for (const {child, column, row} of placements) {
+		const yogaNode = child.yogaNode!;
+		yogaNode.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		yogaNode.setPosition(Yoga.EDGE_LEFT, columnOffsets[column.start] ?? 0);
+		yogaNode.setPosition(Yoga.EDGE_TOP, rowOffsets[row.start] ?? 0);
+		yogaNode.setWidth(spanSize(columnSizes, column.start, column.end, columnGap));
+		yogaNode.setHeight(spanSize(rowSizes, row.start, row.end, rowGap));
+	}
+};
+
+export const calculateLayoutWithGrid = (root: DOMElement, width: number): void => {
+	root.yogaNode!.setWidth(width);
+	root.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+	layoutGrid(root);
+	root.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+};
